@rendermode InteractiveServer
@using sv_aa7ae45d7b9f477db40d52ebfb62a0d8.Models
@using sv_aa7ae45d7b9f477db40d52ebfb62a0d8.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="FilteredTasks("To Do")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="id => MoveTask(id, "In Progress")"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="FilteredTasks("In Progress")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, "To Do")"
                     OnMoveRight="id => MoveTask(id, "Done")"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="Done"
                     Tasks="FilteredTasks("Done")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, "In Progress")"
                     OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask(BoardAddTaskForm.NewTaskRequest request)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(
                request.Title, request.Assignee, request.Priority, request.DueDate);
            // The service returns the task with its default status; override to match the column
            allTasks.Add(newTask with { Status = request.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
"}

